// All clients flattened for VP/Exec
const ALL_CLIENTS_FLAT = [
  ...CRM_CLIENTS["edo-1"],
  ...CRM_CLIENTS["edo-2"],
  ...CRM_CLIENTS["edo-3"],
];

function getClientsForUser(user) {
  if (!user) return [];
  if (user.role === "Exec") return ALL_CLIENTS_FLAT;
  // EVP sees all accounts belonging to their assigned EDOs
  if (user.role === "EVP") {
    const edoIds = new Set(user.edoIds || []);
    return ALL_CLIENTS_FLAT.filter((c) =>
      Object.keys(CRM_CLIENTS).some(
        (k) =>
          edoIds.has(k) && (CRM_CLIENTS[k] || []).some((cl) => cl.id === c.id),
      ),
    );
  }
  // SVP sees only their assigned strategic accounts
  if (user.role === "SVP") {
    const clientIds = new Set(user.clientIds || []);
    return ALL_CLIENTS_FLAT.filter((c) => clientIds.has(c.id));
  }
  if (user.role === "Chaplain") {
    // Return only clients where this chaplain is assigned
    const lastName = user.name.split(" ").slice(-1)[0];
    return ALL_CLIENTS_FLAT.filter((c) =>
      (c.chaplainNames || []).some((n) => n.includes(lastName)),
    );
  }
  return CRM_CLIENTS[user.id] || [];
}

