function parseDuration(dur) {
  if (!dur) return 2;
  if (dur === "Full day") return 8;
  if (dur === "4–6 hours") return 5;
  if (dur === "2–4 hours") return 3;
  if (dur === "1–2 hours") return 1.5;
  return 2;
}
// ── Mock Visit Log Data ───────────────────────────────────────────────────────
function makeMockVisits(allClients) {
  const logs = [];
  const chaplainsByClient = {};
  allClients.forEach((c) => {
    chaplainsByClient[c.id] = c.chaplainNames || [];
  });

  const overviews = [
    "A warm and receptive atmosphere on the floor today. Chaplain presence was well-received. Several employees sought out one-on-one time unprompted, which is a positive sign for program trust.",
    "Heavier emotional climate this visit — several conversations touched on anxiety around upcoming organizational changes. Chaplain team responded with steady, grounded presence.",
    "Strong visit overall. Team morale appeared higher than last quarter. Engagement at lunch areas was particularly rich with informal connections.",
    "Notable uptick in grief-related conversations, likely connected to a loss in the community last week. Pastoral care was the primary focus.",
    "Productive visit with good chaplain visibility. Multiple employees flagged interest in a group session next quarter.",
    "Exceptional engagement today. Employees were eager to connect and the chaplain was able to offer meaningful support across multiple departments.",
    "A quieter visit — many employees were heads-down on a production push. Chaplain focused on brief, intentional check-ins rather than longer conversations.",
    "Crisis follow-up was the primary focus today. The chaplain provided ongoing support to individuals affected by last week's incident.",
    "New employees were especially receptive. Several first-time conversations laid a strong foundation for ongoing chaplain relationships.",
    "Holiday season is clearly affecting morale. Chaplain noted increased loneliness and financial stress themes across multiple conversations.",
  ];
  const reflections = [
    "This was a meaningful visit. I felt genuinely present and sustained by the connections made. The challenge was pacing — so many needs, limited time.",
    "Stretched but not depleted. The heavier conversations reminded me why this work matters. Grateful for a strong chaplain team.",
    "I left feeling encouraged. The receptivity here continues to grow. Personal prayer and preparation beforehand made a difference.",
    "Difficult day emotionally — carried some of the weight home. Will debrief with supervisor and lean on team support.",
    "One of my best visits in months. The trust that has been built here over time is bearing real fruit.",
  ];

  const seed = (s) => {
    let h = 0;
    for (let c of s) h = (h * 31 + c.charCodeAt(0)) & 0xffffffff;
    return Math.abs(h);
  };
  const pick = (arr, s) => arr[Math.abs(s) % arr.length];
  const TYPES = INTERACTION_TYPES.map((t) => t.key);

  let id = 1;

  // Full 12-month calendar: Aug 2024 – Jul 2025
  const months = [
    "2024-08",
    "2024-09",
    "2024-10",
    "2024-11",
    "2024-12",
    "2025-01",
    "2025-02",
    "2025-03",
    "2025-04",
    "2025-05",
    "2025-06",
    "2025-07",
  ];

  // Days in each month (non-leap 2024/2025)
  const daysInMonth = {
    "2024-08": 31,
    "2024-09": 30,
    "2024-10": 31,
    "2024-11": 30,
    "2024-12": 31,
    "2025-01": 31,
    "2025-02": 28,
    "2025-03": 31,
    "2025-04": 30,
    "2025-05": 31,
    "2025-06": 30,
    "2025-07": 31,
  };

  // Generate a realistic spread of visit days for a client in a month
  // Large clients (chaplains >= 5) get 8-12 visits/month
  // Medium clients (chaplains 3-4) get 5-8 visits/month
  // Small clients (chaplains 1-2) get 2-4 visits/month
  function getVisitDays(client, ym) {
    const totalDays = daysInMonth[ym];
    const base = seed(client.id + ym + "days");
    const chaps = client.chaplains || 1;
    const count =
      chaps >= 5
        ? 8 + (base % 5) // 8–12
        : chaps >= 3
          ? 5 + (base % 4) // 5–8
          : 2 + (base % 3); // 2–4

    // Spread visits across the month avoiding weekends (approx) and clustering
    const days = new Set();
    let attempts = 0;
    while (days.size < count && attempts < 100) {
      const d = 1 + (seed(client.id + ym + attempts + "d") % totalDays);
      // Avoid day 1 (often admin) and last day; prefer M-F range simulation
      const dow = new Date(
        `${ym}-${String(d).padStart(2, "0")}T12:00`,
      ).getDay();
      if (dow !== 0 && dow !== 6 && d > 1 && d < totalDays) days.add(d);
      attempts++;
    }
    // If we didn't get enough, fill remaining without weekend filter
    while (days.size < count && attempts < 200) {
      const d = 1 + (seed(client.id + ym + attempts + "fill") % totalDays);
      if (d > 1 && d < totalDays) days.add(d);
      attempts++;
    }
    return Array.from(days).sort((a, b) => a - b);
  }

  allClients.forEach((client) => {
    const chaps = chaplainsByClient[client.id] || ["Chaplain"];
    months.forEach((ym) => {
      const visitDays = getVisitDays(client, ym);
      visitDays.forEach((day, vi) => {
        const dateStr = `${ym}-${String(day).padStart(2, "0")}`;
        const s = seed(client.id + dateStr + vi);

        // More chaplains present on larger visits
        const maxChaps = Math.min(chaps.length, client.chaplains >= 5 ? 3 : 2);
        const chaplainCount = 1 + (s % maxChaps);
        // Rotate which chaplains show up to create variety
        const startIdx = s % chaps.length;
        const presentChaplains = [];
        for (let ci = 0; ci < chaplainCount; ci++) {
          presentChaplains.push(chaps[(startIdx + ci) % chaps.length]);
        }

        // Conversations — structured by CONVERSATION_SECTIONS
        const conversations = {};
        let total = 0;
        CONVERSATION_SECTIONS.forEach((section, si) => {
          conversations[section.key] = {};
          section.types.forEach((type, ti) => {
            const n = seed(client.id + dateStr + si + ti);
            // Sparse: ~30% of types have a non-zero count
            if (n % 3 === 0) {
              const maxCount =
                section.key === "confidential"
                  ? client.employees > 1000
                    ? 8
                    : client.employees > 500
                      ? 5
                      : 3
                  : client.employees > 1000
                    ? 4
                    : 2;
              const cnt = 1 + (n % maxCount);
              conversations[section.key][type] = cnt;
              total += cnt;
            }
          });
        });
        // Keep a flat interactions map for backward compatibility with metrics / charts
        const interactions = {};
        const LEGACY_MAP = {
          "Grief/Death": "grief",
          Stress: "stress",
          Family: "family",
          "Health/Illness": "health",
          Finances: "financial",
          Anger: "conflict",
          Faith: "spiritual",
          "Positive Discussions": "celebration",
          Counseling: "referral",
        };
        Object.entries(conversations.confidential || {}).forEach(([k, v]) => {
          const legacyKey = LEGACY_MAP[k] || "supportive";
          interactions[legacyKey] = (interactions[legacyKey] || 0) + v;
        });

        // Duration varies by client size and visit type
        const durPool =
          client.employees > 2000
            ? ["2–4 hours", "4–6 hours", "4–6 hours", "Full day", "Full day"]
            : client.employees > 800
              ? ["1–2 hours", "2–4 hours", "2–4 hours", "4–6 hours", "Full day"]
              : [
                  "1–2 hours",
                  "1–2 hours",
                  "2–4 hours",
                  "2–4 hours",
                  "4–6 hours",
                ];
        const duration = pick(durPool, s);

        const visitTypePool = [
          "Scheduled Visit",
          "Scheduled Visit",
          "Scheduled Visit",
          "Follow-up Visit",
          "Chaplain Check-in",
          "Crisis Response",
        ];
        const hasIssue = s % 11 === 0; // ~9% have a flagged issue
        const followUpNeeded = s % 5 === 0;

        logs.push({
          id: String(id++),
          date: dateStr,
          clientId: client.id,
          clientName: client.name,
          clientColor: client.color,
          clientLogo: client.logo,
          chaplains: presentChaplains,
          visitType: pick(visitTypePool, s),
          duration,
          totalEmployees: Math.round(
            client.employees * (0.03 + (s % 10) * 0.01),
          ),
          interactions, // legacy flat map (used by metrics/charts)
          conversations, // structured by CONVERSATION_SECTIONS (used by report detail)
          totalInteractions: total,
          followUpNeeded,
          followUpNotes: followUpNeeded
            ? "Employee in difficult season — check in next visit. Referral to EAP being arranged."
            : "",
          periodOverview: pick(overviews, s),
          ministryStory: pick(
            [
              "An employee pulled me aside near the end of the shift. She said she'd been struggling quietly for months and hadn't told anyone. The fact that a chaplain was simply present and available gave her the courage to speak. We talked for twenty minutes. She left lighter.",
              "One of the longer-tenured workers stopped me by the lockers. His father passed last month. He didn't want resources — he just needed someone to listen. I stayed with him for half an hour. He shook my hand before I left.",
              "During a lunch break, a small group of workers started asking genuine questions about faith and meaning. What started as casual turned into a real conversation about purpose. One man said it was the first time he'd talked about anything like that at work.",
              "A new hire, barely two weeks in, came to me visibly anxious. She was worried she'd made a mistake taking this job. We talked through it. By the end she said she felt more settled. Sometimes that's what it takes — just being heard.",
              "A supervisor I've seen many times finally opened up. He's been carrying the weight of a struggling team alone. He cried briefly, then apologized. I told him that kind of honesty takes real strength. He seemed genuinely surprised to hear that.",
            ],
            s,
          ),
          recommendations:
            "Continue regular presence. Consider group session offering next quarter. Follow up with HR contact on referral outcomes.",
          personalReflection: pick(reflections, s),
          siteWellbeing: String(3 + (s % 3)),
          availabilityNext: "Full availability",
          flagIncident: hasIssue,
          issues: hasIssue
            ? [
                {
                  id: "i1",
                  category: pick(ERROR_CATEGORIES, s + 3),
                  severity: pick(["low", "medium", "high"], s + 1),
                  description: pick(
                    [
                      "Access to the east wing was restricted without prior notice, limiting chaplain rounds for approximately 45 minutes.",
                      "A scheduling miscommunication resulted in the chaplain arriving during a mandatory all-hands meeting.",
                      "An employee in distress required extended support — chaplain stayed two additional hours beyond scheduled visit.",
                      "Safety concern reported by employee — chaplain documented and escalated to site coordinator per protocol.",
                    ],
                    s + 5,
                  ),
                  resolution:
                    "Coordinator contacted — issue resolved for future visits.",
                  reportToVP: s % 3 === 0,
                },
              ]
            : [],
          activityHrs: parseFloat(
            (parseDuration(pick(durPool, s)) * (0.65 + (s % 8) * 0.04)).toFixed(
              1,
            ),
          ),
          travelHrs: parseFloat(
            (parseDuration(pick(durPool, s)) * (0.15 + (s % 5) * 0.02)).toFixed(
              1,
            ),
          ),
          expenses: s % 3 === 0 ? parseFloat((15 + (s % 60)).toFixed(2)) : 0,
          jri: 1 + (s % 6),
          submittedDays: s % 5,
          onTime: s % 5 <= 3,
        });
      });
    });
  });

  return logs.sort((a, b) => b.date.localeCompare(a.date));
}

// Shared visit data (module-level so it persists across renders in demo)
let VISIT_LOG_SEED = null;
function getVisitLog(allClients) {
  if (!VISIT_LOG_SEED) VISIT_LOG_SEED = makeMockVisits(allClients);
  return VISIT_LOG_SEED;
}

// ── Visit Detail Modal ────────────────────────────────────────────────────────
function VisitDetailModal({ visit, onClose }) {
  const [tab, setTab] = useState("summary");
  if (!visit) return null;
  const cc = visit.clientColor;
  const totalInteractions = visit.totalInteractions;

  const TABS = [
    ["summary", "Summary"],
    ["conversations", "Conversations"],
    ["narrative", "Reflection"],
    [
      "issues",
      "Issues" + (visit.issues.length ? ` (${visit.issues.length})` : ""),
    ],
  ];
  const SEVERITY = {
    low: { bg: "#eafaf1", text: "#1e8449" },
    medium: { bg: "#fef9e7", text: "#9a6e00" },
    high: { bg: "#fdedec", text: "#922b21" },
  };

  return (
    <div
      onClick={onClose}
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(10,20,40,0.55)",
        zIndex: 600,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 24,
        backdropFilter: "blur(3px)",
      }}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          background: "#fff",
          borderRadius: 16,
          width: "100%",
          maxWidth: 680,
          maxHeight: "90vh",
          overflow: "hidden",
          boxShadow: "0 24px 64px rgba(0,0,0,0.22)",
          display: "flex",
          flexDirection: "column",
        }}
      >
        {/* Modal header */}
        <div
          style={{
            background: `linear-gradient(135deg,${cc},${cc}dd)`,
            padding: "20px 24px",
            color: "#fff",
            flexShrink: 0,
          }}
        >
          <div
            style={{
              display: "flex",
              alignItems: "flex-start",
              justifyContent: "space-between",
            }}
          >
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              <div
                style={{
                  width: 42,
                  height: 42,
                  borderRadius: 10,
                  background: "rgba(255,255,255,0.2)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: 16,
                  fontWeight: 700,
                  border: "2px solid rgba(255,255,255,0.35)",
                }}
              >
                {visit.clientLogo}
              </div>
              <div>
                <div
                  style={{
                    fontSize: 17,
                    fontWeight: 700,
                    fontFamily: "'Georgia',serif",
                  }}
                >
                  {visit.clientName}
                </div>
                <div style={{ fontSize: 12, opacity: 0.85, marginTop: 2 }}>
                  {formatDate(visit.date)} · {visit.visitType} ·{" "}
                  {visit.duration}
                </div>
              </div>
            </div>
            <button
              onClick={onClose}
              style={{
                border: "none",
                background: "rgba(255,255,255,0.2)",
                borderRadius: 8,
                width: 32,
                height: 32,
                cursor: "pointer",
                fontSize: 16,
                color: "#fff",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              ✕
            </button>
          </div>
          {/* Quick stats row */}
          <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
            {[
              [totalInteractions, "Conversations"],
              [visit.totalEmployees, "Employees"],
              [
                visit.chaplains.length,
                "Chaplain" + (visit.chaplains.length !== 1 ? "s" : ""),
              ],
              [visit.onTime ? "On-Time" : "Late", "Submission"],
            ].map(([v, l], i) => (
              <div
                key={i}
                style={{
                  background: "rgba(255,255,255,0.15)",
                  borderRadius: 8,
                  padding: "7px 12px",
                  fontSize: 12,
                }}
              >
                <span style={{ fontWeight: 700 }}>{v}</span>{" "}
                <span style={{ opacity: 0.8 }}>{l}</span>
              </div>
            ))}
            {visit.flagIncident && (
              <div
                style={{
                  background: "rgba(231,76,60,0.4)",
                  borderRadius: 8,
                  padding: "7px 12px",
                  fontSize: 12,
                  fontWeight: 700,
                }}
              >
                ⚠️ Incident Flagged
              </div>
            )}
          </div>
        </div>

        {/* Tabs */}
        <div
          style={{
            display: "flex",
            borderBottom: "1px solid #e8edf2",
            padding: "0 24px",
            background: "#fafbfd",
            flexShrink: 0,
          }}
        >
          {TABS.map(([key, label]) => (
            <button
              key={key}
              onClick={() => setTab(key)}
              style={{
                padding: "11px 16px",
                border: "none",
                background: "transparent",
                fontSize: 13,
                fontWeight: tab === key ? 700 : 400,
                color: tab === key ? cc : "#6b7a8d",
                borderBottom:
                  tab === key ? `2px solid ${cc}` : "2px solid transparent",
                cursor: "pointer",
                marginBottom: -1,
              }}
            >
              {label}
            </button>
          ))}
        </div>

        <div style={{ flex: 1, overflow: "auto", padding: "20px 24px" }}>
          {tab === "summary" && (
            <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
              <div
                style={{
                  display: "grid",
                  gridTemplateColumns: "1fr 1fr",
                  gap: 12,
                }}
              >
                {[
                  ["Date", formatDate(visit.date)],
                  ["Visit Type", visit.visitType],
                  ["Employees Engaged", visit.totalEmployees],
                  [
                    "Site Wellbeing",
                    visit.siteWellbeing ? `${visit.siteWellbeing}/5` : "—",
                  ],
                ].map(([l, v], i) => (
                  <div
                    key={i}
                    style={{
                      background: "#f7f9fc",
                      borderRadius: 8,
                      padding: "12px 14px",
                    }}
                  >
                    <div
                      style={{
                        fontSize: 11,
                        color: "#9aa8b8",
                        textTransform: "uppercase",
                        letterSpacing: "0.07em",
                        marginBottom: 4,
                      }}
                    >
                      {l}
                    </div>
                    <div
                      style={{
                        fontSize: 14,
                        fontWeight: 600,
                        color: "#1a2a3a",
                      }}
                    >
                      {v}
                    </div>
                  </div>
                ))}
              </div>
              {visit.followUpNeeded && (
                <div
                  style={{
                    background: "#fef9e7",
                    borderRadius: 10,
                    padding: "14px 16px",
                    border: "1px solid #f0d98a",
                  }}
                >
                  <div
                    style={{
                      fontSize: 12,
                      fontWeight: 700,
                      color: "#7a4f00",
                      marginBottom: 6,
                      textTransform: "uppercase",
                      letterSpacing: "0.07em",
                    }}
                  >
                    ⏰ Follow-up Required
                  </div>
                  <div
                    style={{ fontSize: 13, color: "#2c2416", lineHeight: 1.6 }}
                  >
                    {visit.followUpNotes}
                  </div>
                </div>
              )}
              <div
                style={{
                  background: "#f7f9fc",
                  borderRadius: 10,
                  padding: "14px 16px",
                }}
              >
                <div
                  style={{
                    fontSize: 12,
                    fontWeight: 700,
                    color: "#9aa8b8",
                    textTransform: "uppercase",
                    letterSpacing: "0.07em",
                    marginBottom: 8,
                  }}
                >
                  Period Overview
                </div>
                <div
                  style={{ fontSize: 13, color: "#2c3e50", lineHeight: 1.7 }}
                >
                  {visit.periodOverview}
                </div>
              </div>
            </div>
          )}

          {tab === "conversations" && (
            <div>
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "space-between",
                  marginBottom: 16,
                }}
              >
                <div
                  style={{ fontSize: 15, fontWeight: 700, color: "#1a2a3a" }}
                >
                  Conversation Breakdown
                </div>
                <div
                  style={{
                    fontSize: 20,
                    fontWeight: 700,
                    color: cc,
                    fontFamily: "'Georgia',serif",
                  }}
                >
                  {totalInteractions} total
                </div>
              </div>
              {CONVERSATION_SECTIONS.map((section) => {
                const sectionData = visit.conversations?.[section.key] || {};
                const entries = Object.entries(sectionData).filter(
                  ([, v]) => v > 0,
                );
                if (entries.length === 0) return null;
                const sectionTotal = entries.reduce((a, [, v]) => a + v, 0);
                return (
                  <div key={section.key} style={{ marginBottom: 14 }}>
                    <div
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: 8,
                        marginBottom: 8,
                      }}
                    >
                      <span style={{ fontSize: 14 }}>{section.icon}</span>
                      <span
                        style={{
                          fontSize: 12,
                          fontWeight: 700,
                          color: section.color,
                          textTransform: "uppercase",
                          letterSpacing: "0.06em",
                        }}
                      >
                        {section.label}
                      </span>
                      <span
                        style={{
                          fontSize: 11,
                          background: section.color + "18",
                          color: section.color,
                          padding: "1px 8px",
                          borderRadius: 10,
                          fontWeight: 700,
                          marginLeft: "auto",
                        }}
                      >
                        {sectionTotal}
                      </span>
                    </div>
                    <div
                      style={{
                        display: "grid",
                        gridTemplateColumns: "repeat(2,1fr)",
                        gap: 6,
                      }}
                    >
                      {entries.map(([type, count]) => (
                        <div
                          key={type}
                          style={{
                            background: "#f7f9fc",
                            borderRadius: 8,
                            padding: "8px 12px",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "space-between",
                            border: `1px solid ${section.color}22`,
                          }}
                        >
                          <span style={{ fontSize: 12, color: "#4a5568" }}>
                            {type}
                          </span>
                          <span
                            style={{
                              fontSize: 14,
                              fontWeight: 700,
                              color: section.color,
                              fontFamily: "'Georgia',serif",
                            }}
                          >
                            {count}
                          </span>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
              {totalInteractions === 0 && (
                <div
                  style={{
                    textAlign: "center",
                    padding: "40px",
                    color: "#9aa8b8",
                  }}
                >
                  No conversation types logged
                </div>
              )}
            </div>
          )}

          {tab === "narrative" && (
            <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
              {[
                ["Period Overview", visit.periodOverview],
                ["Ministry Story", visit.ministryStory],
                ["Recommendations", visit.recommendations],
                ["Personal Reflection", visit.personalReflection],
              ]
                .filter(([, v]) => v)
                .map(([l, v], i) => (
                  <div
                    key={i}
                    style={{
                      background: "#f7f9fc",
                      borderRadius: 10,
                      padding: "14px 16px",
                    }}
                  >
                    <div
                      style={{
                        fontSize: 11,
                        fontWeight: 700,
                        color: "#9aa8b8",
                        textTransform: "uppercase",
                        letterSpacing: "0.07em",
                        marginBottom: 8,
                      }}
                    >
                      {l}
                    </div>
                    <div
                      style={{
                        fontSize: 13,
                        color: "#2c3e50",
                        lineHeight: 1.75,
                      }}
                    >
                      {v}
                    </div>
                  </div>
                ))}
            </div>
          )}

          {tab === "issues" &&
            (visit.issues.length > 0 ? (
              <div
                style={{ display: "flex", flexDirection: "column", gap: 10 }}
              >
                {visit.issues.map((issue) => {
                  const sv = SEVERITY[issue.severity] || SEVERITY.medium;
                  return (
                    <div
                      key={issue.id}
                      style={{
                        borderRadius: 10,
                        overflow: "hidden",
                        border: `1.5px solid ${sv.text}44`,
                      }}
                    >
                      <div
                        style={{
                          padding: "10px 14px",
                          background: sv.bg,
                          display: "flex",
                          alignItems: "center",
                          gap: 8,
                        }}
                      >
                        <span>
                          {issue.severity === "high"
                            ? "🔴"
                            : issue.severity === "medium"
                              ? "🟡"
                              : "🟢"}
                        </span>
                        <span
                          style={{
                            fontSize: 13,
                            fontWeight: 700,
                            color: sv.text,
                          }}
                        >
                          {issue.category}
                        </span>
                        <span
                          style={{
                            fontSize: 11,
                            background: "rgba(0,0,0,0.07)",
                            color: sv.text,
                            padding: "2px 8px",
                            borderRadius: 10,
                            textTransform: "capitalize",
                          }}
                        >
                          {issue.severity}
                        </span>
                      </div>
                      <div style={{ padding: "12px 14px", background: "#fff" }}>
                        <div
                          style={{
                            fontSize: 13,
                            color: "#2c3e50",
                            lineHeight: 1.6,
                            marginBottom: issue.resolution ? 8 : 0,
                          }}
                        >
                          {issue.description}
                        </div>
                        {issue.resolution && (
                          <div
                            style={{
                              fontSize: 12,
                              color: "#6b7a8d",
                              fontStyle: "italic",
                            }}
                          >
                            → {issue.resolution}
                          </div>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            ) : (
              <div
                style={{
                  textAlign: "center",
                  padding: "48px 20px",
                  color: "#9aa8b8",
                }}
              >
                <div style={{ fontSize: 36, marginBottom: 10 }}>✅</div>
                <div
                  style={{ fontSize: 15, fontWeight: 600, color: "#6b7a8d" }}
                >
                  No issues reported for this visit
                </div>
              </div>
            ))}
        </div>
      </div>
    </div>
  );
}

// ── Visit Log Page ────────────────────────────────────────────────────────────
function VisitLogPage({ user, allClients, onBack }) {
  const cc = "#1a4a7a";
  const allVisits = getVisitLog(allClients);

  // Role-scoped filtering
  const myVisits = allVisits.filter((v) => {
    if (user.role === "EVP" || user.role === "SVP" || user.role === "Exec")
      return true;
    if (user.role === "Chaplain") {
      return v.chaplains.some((c) =>
        c.includes(user.name.split(" ").slice(-1)[0]),
      );
    }
    // EDO — see visits for their clients
    const myClientIds = allClients.map((c) => c.id);
    return myClientIds.includes(v.clientId);
  });

  const [search, setSearch] = useState("");
  const [filterClient, setFilterClient] = useState("all");
  const [filterChaplain, setFilterChaplain] = useState("all");
  const [filterMonth, setFilterMonth] = useState("all");
  const [filterOnTime, setFilterOnTime] = useState("all");
  const [selectedVisit, setSelectedVisit] = useState(null);
  const [viewMode, setViewMode] = useState("list"); // "list" | "grid"

  const clientOptions = [...new Set(myVisits.map((v) => v.clientName))].sort();
  const chaplainOptions = [
    ...new Set(myVisits.flatMap((v) => v.chaplains)),
  ].sort();
  const monthOptions = [...new Set(myVisits.map((v) => v.date.slice(0, 7)))]
    .sort()
    .reverse();

  const filtered = myVisits.filter((v) => {
    if (filterClient !== "all" && v.clientName !== filterClient) return false;
    if (filterChaplain !== "all" && !v.chaplains.includes(filterChaplain))
      return false;
    if (filterMonth !== "all" && !v.date.startsWith(filterMonth)) return false;
    if (filterOnTime === "ontime" && !v.onTime) return false;
    if (filterOnTime === "late" && v.onTime) return false;
    if (search) {
      const q = search.toLowerCase();
      return (
        v.clientName.toLowerCase().includes(q) ||
        v.chaplains.some((c) => c.toLowerCase().includes(q)) ||
        v.visitType.toLowerCase().includes(q) ||
        v.periodOverview.toLowerCase().includes(q)
      );
    }
    return true;
  });

  const totalConversations = filtered.reduce(
    (s, v) => s + v.totalInteractions,
    0,
  );
  const totalEmployees = filtered.reduce((s, v) => s + v.totalEmployees, 0);
  const onTimeCount = filtered.filter((v) => v.onTime).length;
  const flaggedCount = filtered.filter((v) => v.flagIncident).length;

  const VisitCard = ({ visit }) => {
    const h = {
      green: { bg: "#eafaf1", text: "#1e8449", dot: "#27ae60" },
      yellow: { bg: "#fef9e7", text: "#9a6e00", dot: "#f39c12" },
      red: { bg: "#fdedec", text: "#922b21", dot: "#e74c3c" },
    };
    const timingStyle = visit.onTime ? h.green : h.red;
    const topTypes = Object.entries(visit.interactions)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 3);
    return (
      <div
        onClick={() => setSelectedVisit(visit)}
        style={{
          background: "#fff",
          borderRadius: 12,
          border: "1px solid #e0e6ef",
          cursor: "pointer",
          overflow: "hidden",
          transition: "all 0.15s",
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.boxShadow = "0 4px 20px rgba(0,0,0,0.10)";
          e.currentTarget.style.borderColor = visit.clientColor;
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.boxShadow = "none";
          e.currentTarget.style.borderColor = "#e0e6ef";
        }}
      >
        <div
          style={{
            height: 4,
            background: `linear-gradient(90deg,${visit.clientColor},${visit.clientColor}88)`,
          }}
        />
        <div style={{ padding: "16px" }}>
          <div
            style={{
              display: "flex",
              alignItems: "flex-start",
              justifyContent: "space-between",
              marginBottom: 10,
            }}
          >
            <div style={{ display: "flex", alignItems: "center", gap: 9 }}>
              <div
                style={{
                  width: 34,
                  height: 34,
                  borderRadius: 8,
                  background: visit.clientColor + "18",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: 12,
                  fontWeight: 700,
                  color: visit.clientColor,
                  flexShrink: 0,
                }}
              >
                {visit.clientLogo}
              </div>
              <div>
                <div
                  style={{
                    fontSize: 13,
                    fontWeight: 700,
                    color: "#1a2a3a",
                    lineHeight: 1.2,
                  }}
                >
                  {visit.clientName}
                </div>
                <div style={{ fontSize: 11, color: "#9aa8b8", marginTop: 1 }}>
                  {formatDate(visit.date)}
                </div>
              </div>
            </div>
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                alignItems: "flex-end",
                gap: 4,
              }}
            >
              <div
                style={{
                  fontSize: 11,
                  fontWeight: 700,
                  padding: "3px 8px",
                  borderRadius: 10,
                  background: timingStyle.bg,
                  color: timingStyle.text,
                }}
              >
                {visit.onTime ? "On-Time" : "Late"}
              </div>
              {visit.flagIncident && (
                <div
                  style={{
                    fontSize: 10,
                    fontWeight: 700,
                    padding: "2px 7px",
                    borderRadius: 10,
                    background: "#fdedec",
                    color: "#922b21",
                  }}
                >
                  ⚠️ Flagged
                </div>
              )}
            </div>
          </div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(3,1fr)",
              gap: 6,
              marginBottom: 10,
            }}
          >
            {[
              [visit.totalInteractions, "Conversations"],
              [visit.totalEmployees, "Employees"],
              [
                visit.chaplains.length,
                "Chaplain" + (visit.chaplains.length !== 1 ? "s" : ""),
              ],
            ].map(([v, l], i) => (
              <div
                key={i}
                style={{
                  background: "#f7f9fc",
                  borderRadius: 6,
                  padding: "7px 8px",
                  textAlign: "center",
                }}
              >
                <div
                  style={{
                    fontSize: 15,
                    fontWeight: 700,
                    color: visit.clientColor,
                  }}
                >
                  {v}
                </div>
                <div style={{ fontSize: 10, color: "#9aa8b8", marginTop: 1 }}>
                  {l}
                </div>
              </div>
            ))}
          </div>
          {topTypes.length > 0 && (
            <div
              style={{
                display: "flex",
                flexWrap: "wrap",
                gap: 4,
                marginBottom: 8,
              }}
            >
              {topTypes.map(([k, count]) => {
                const t = INTERACTION_TYPES.find((t) => t.key === k);
                return t ? (
                  <div
                    key={k}
                    style={{
                      fontSize: 11,
                      padding: "3px 8px",
                      borderRadius: 8,
                      background: "#f0f4f8",
                      color: "#6b7a8d",
                      display: "flex",
                      alignItems: "center",
                      gap: 4,
                    }}
                  >
                    <span>{t.icon}</span>
                    {t.label}{" "}
                    <strong style={{ color: visit.clientColor }}>
                      {count}
                    </strong>
                  </div>
                ) : null;
              })}
            </div>
          )}
          <div
            style={{
              fontSize: 11,
              color: "#9aa8b8",
              lineHeight: 1.5,
              overflow: "hidden",
              display: "-webkit-box",
              WebkitLineClamp: 2,
              WebkitBoxOrient: "vertical",
            }}
          >
            {visit.periodOverview}
          </div>
        </div>
      </div>
    );
  };

  const VisitRow = ({ visit }) => {
    const timingStyle = visit.onTime
      ? { bg: "#eafaf1", text: "#1e8449" }
      : { bg: "#fdedec", text: "#922b21" };
    return (
      <div
        onClick={() => setSelectedVisit(visit)}
        style={{
          display: "grid",
          gridTemplateColumns:
            "36px 1.6fr 1.2fr 0.8fr 80px 80px 80px 80px 40px",
          gap: 12,
          alignItems: "center",
          padding: "12px 16px",
          borderRadius: 10,
          border: "1px solid #e8edf2",
          marginBottom: 6,
          cursor: "pointer",
          background: "#fff",
          transition: "all 0.12s",
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.borderColor = visit.clientColor;
          e.currentTarget.style.boxShadow = "0 2px 12px rgba(0,0,0,0.07)";
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.borderColor = "#e8edf2";
          e.currentTarget.style.boxShadow = "none";
        }}
      >
        <div
          style={{
            width: 32,
            height: 32,
            borderRadius: 7,
            background: visit.clientColor + "18",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 11,
            fontWeight: 700,
            color: visit.clientColor,
          }}
        >
          {visit.clientLogo}
        </div>
        <div>
          <div style={{ fontSize: 13, fontWeight: 700, color: "#1a2a3a" }}>
            {visit.clientName}
          </div>
          <div style={{ fontSize: 11, color: "#9aa8b8" }}>
            {visit.visitType}
          </div>
        </div>
        <div style={{ fontSize: 12, color: "#6b7a8d" }}>
          {visit.chaplains.slice(0, 2).join(", ")}
          {visit.chaplains.length > 2 ? ` +${visit.chaplains.length - 2}` : ""}
        </div>
        <div style={{ fontSize: 12, color: "#6b7a8d" }}>
          {formatDate(visit.date)}
        </div>
        <div
          style={{
            textAlign: "center",
            fontSize: 14,
            fontWeight: 700,
            color: cc,
          }}
        >
          {visit.totalInteractions}
        </div>
        <div
          style={{
            textAlign: "center",
            fontSize: 14,
            fontWeight: 700,
            color: "#6b7a8d",
          }}
        >
          {visit.totalEmployees}
        </div>
        <div style={{ textAlign: "center" }}>
          <span
            style={{
              fontSize: 11,
              fontWeight: 700,
              padding: "3px 8px",
              borderRadius: 10,
              background: timingStyle.bg,
              color: timingStyle.text,
            }}
          >
            {visit.onTime ? "✓ On-Time" : "Late"}
          </span>
        </div>
        <div style={{ textAlign: "center" }}>
          {visit.flagIncident && (
            <span
              style={{
                fontSize: 11,
                fontWeight: 700,
                padding: "3px 8px",
                borderRadius: 10,
                background: "#fdedec",
                color: "#922b21",
              }}
            >
              ⚠️
            </span>
          )}
        </div>
        <div style={{ fontSize: 18, color: "#d0dae6", textAlign: "right" }}>
          ›
        </div>
      </div>
    );
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "#f0f4f8",
        fontFamily: "'Helvetica Neue',Arial,sans-serif",
      }}
    >
      {selectedVisit && (
        <VisitDetailModal
          visit={selectedVisit}
          onClose={() => setSelectedVisit(null)}
        />
      )}

      {/* Sub-header */}
      <div
        style={{
          background: "#fff",
          borderBottom: "1px solid #e0e6ef",
          padding: "0 28px",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          height: 52,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <button
            onClick={onBack}
            style={{
              border: "none",
              background: "transparent",
              cursor: "pointer",
              fontSize: 13,
              color: "#6b7a8d",
              display: "flex",
              alignItems: "center",
              gap: 6,
            }}
          >
            ← Dashboard
          </button>
          <div style={{ width: 1, height: 20, background: "#e0e6ef" }} />
          <div style={{ fontSize: 15, fontWeight: 700, color: "#1a2a3a" }}>
            Visit Log
          </div>
          <div style={{ fontSize: 12, color: "#9aa8b8" }}>
            · {myVisits.length} visits on record
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          {["list", "grid"].map((m) => (
            <button
              key={m}
              onClick={() => setViewMode(m)}
              style={{
                padding: "5px 10px",
                borderRadius: 6,
                border: "1px solid",
                borderColor: viewMode === m ? cc : "#e0e6ef",
                background: viewMode === m ? cc : "transparent",
                color: viewMode === m ? "#fff" : "#6b7a8d",
                fontSize: 12,
                cursor: "pointer",
              }}
            >
              {m === "list" ? "☰ List" : "⊞ Grid"}
            </button>
          ))}
        </div>
      </div>

      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "24px 20px" }}>
        {/* Summary KPI bar */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(4,1fr)",
            gap: 12,
            marginBottom: 24,
          }}
        >
          {[
            [
              "Visits Shown",
              filtered.length,
              cc,
              "of " + myVisits.length + " total",
            ],
            [
              "Total Conversations",
              totalConversations.toLocaleString(),
              cc,
              "across all visits",
            ],
            [
              "On-Time Submissions",
              `${filtered.length ? Math.round((onTimeCount / filtered.length) * 100) : 0}%`,
              onTimeCount / Math.max(filtered.length, 1) >= 0.85
                ? "#27ae60"
                : "#f39c12",
              `${onTimeCount} of ${filtered.length}`,
            ],
            [
              "Flagged Incidents",
              flaggedCount,
              flaggedCount > 0 ? "#e74c3c" : "#27ae60",
              flaggedCount > 0 ? "Needs attention" : "All clear",
            ],
          ].map(([l, v, c, sub], i) => (
            <div
              key={i}
              style={{
                background: "#fff",
                borderRadius: 12,
                padding: "16px 18px",
                border: "1px solid #e0e6ef",
                borderTop: `3px solid ${c}`,
              }}
            >
              <div
                style={{
                  fontSize: 26,
                  fontWeight: 700,
                  color: c,
                  fontFamily: "'Georgia',serif",
                }}
              >
                {v}
              </div>
              <div
                style={{
                  fontSize: 13,
                  fontWeight: 600,
                  color: "#1a2a3a",
                  marginTop: 3,
                }}
              >
                {l}
              </div>
              <div style={{ fontSize: 11, color: "#9aa8b8", marginTop: 2 }}>
                {sub}
              </div>
            </div>
          ))}
        </div>

        {/* Filters */}
        <div
          style={{
            background: "#fff",
            borderRadius: 12,
            border: "1px solid #e0e6ef",
            padding: "16px 18px",
            marginBottom: 20,
            display: "flex",
            flexWrap: "wrap",
            gap: 10,
            alignItems: "center",
          }}
        >
          <div
            style={{ position: "relative", flex: "1 1 220px", minWidth: 180 }}
          >
            <span
              style={{
                position: "absolute",
                left: 10,
                top: "50%",
                transform: "translateY(-50%)",
                fontSize: 13,
                color: "#9aa8b8",
              }}
            >
              🔍
            </span>
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search visits, clients, chaplains..."
              style={{
                width: "100%",
                padding: "8px 10px 8px 30px",
                borderRadius: 8,
                border: "1px solid #d0dae6",
                fontSize: 13,
                color: "#1a2a3a",
                background: "#f7f9fc",
                outline: "none",
                boxSizing: "border-box",
              }}
            />
          </div>
          {user.role !== "Chaplain" && (
            <select
              value={filterChaplain}
              onChange={(e) => setFilterChaplain(e.target.value)}
              style={{
                padding: "8px 12px",
                borderRadius: 8,
                border: "1px solid #d0dae6",
                fontSize: 13,
                color: "#1a2a3a",
                background: "#f7f9fc",
                cursor: "pointer",
              }}
            >
              <option value="all">All Chaplains</option>
              {chaplainOptions.map((c) => (
                <option key={c} value={c}>
                  {c}
                </option>
              ))}
            </select>
          )}
          {(user.role === "EVP" ||
            user.role === "SVP" ||
            user.role === "Exec") && (
            <select
              value={filterClient}
              onChange={(e) => setFilterClient(e.target.value)}
              style={{
                padding: "8px 12px",
                borderRadius: 8,
                border: "1px solid #d0dae6",
                fontSize: 13,
                color: "#1a2a3a",
                background: "#f7f9fc",
                cursor: "pointer",
              }}
            >
              <option value="all">All Clients</option>
              {clientOptions.map((c) => (
                <option key={c} value={c}>
                  {c}
                </option>
              ))}
            </select>
          )}
          <select
            value={filterMonth}
            onChange={(e) => setFilterMonth(e.target.value)}
            style={{
              padding: "8px 12px",
              borderRadius: 8,
              border: "1px solid #d0dae6",
              fontSize: 13,
              color: "#1a2a3a",
              background: "#f7f9fc",
              cursor: "pointer",
            }}
          >
            <option value="all">All Months</option>
            {monthOptions.map((m) => (
              <option key={m} value={m}>
                {new Date(m + "-15").toLocaleDateString("en-US", {
                  month: "long",
                  year: "numeric",
                })}
              </option>
            ))}
          </select>
          <select
            value={filterOnTime}
            onChange={(e) => setFilterOnTime(e.target.value)}
            style={{
              padding: "8px 12px",
              borderRadius: 8,
              border: "1px solid #d0dae6",
              fontSize: 13,
              color: "#1a2a3a",
              background: "#f7f9fc",
              cursor: "pointer",
            }}
          >
            <option value="all">All Submissions</option>
            <option value="ontime">On-Time Only</option>
            <option value="late">Late Only</option>
          </select>
          {(search ||
            filterClient !== "all" ||
            filterChaplain !== "all" ||
            filterMonth !== "all" ||
            filterOnTime !== "all") && (
            <button
              onClick={() => {
                setSearch("");
                setFilterClient("all");
                setFilterChaplain("all");
                setFilterMonth("all");
                setFilterOnTime("all");
              }}
              style={{
                padding: "8px 14px",
                borderRadius: 8,
                border: "1px solid #e74c3c",
                background: "transparent",
                color: "#e74c3c",
                fontSize: 12,
                fontWeight: 600,
                cursor: "pointer",
              }}
            >
              Clear Filters
            </button>
          )}
          <div style={{ marginLeft: "auto", fontSize: 12, color: "#9aa8b8" }}>
            <strong style={{ color: "#1a2a3a" }}>{filtered.length}</strong>{" "}
            visits
          </div>
        </div>

        {/* List view headers */}
        {viewMode === "list" && filtered.length > 0 && (
          <div
            style={{
              display: "grid",
              gridTemplateColumns:
                "36px 1.6fr 1.2fr 0.8fr 80px 80px 80px 80px 40px",
              gap: 12,
              padding: "6px 16px",
              marginBottom: 4,
            }}
          >
            {[
              "",
              "Client",
              "Chaplain(s)",
              "Date",
              "Conv.",
              "Employees",
              "Timing",
              "Flags",
              "",
            ].map((h, i) => (
              <div
                key={i}
                style={{
                  fontSize: 10,
                  fontWeight: 700,
                  color: "#9aa8b8",
                  textTransform: "uppercase",
                  letterSpacing: "0.07em",
                  textAlign: i >= 4 && i <= 7 ? "center" : "left",
                }}
              >
                {h}
              </div>
            ))}
          </div>
        )}

        {/* Results */}
        {filtered.length === 0 ? (
          <div
            style={{
              textAlign: "center",
              padding: "60px 20px",
              background: "#fff",
              borderRadius: 12,
              border: "1px solid #e0e6ef",
              color: "#9aa8b8",
            }}
          >
            <div style={{ fontSize: 36, marginBottom: 12 }}>📋</div>
            <div
              style={{
                fontSize: 16,
                fontWeight: 600,
                color: "#6b7a8d",
                marginBottom: 6,
              }}
            >
              No visits match your filters
            </div>
            <div style={{ fontSize: 13 }}>
              Try adjusting your search or clearing filters
            </div>
          </div>
        ) : viewMode === "list" ? (
          filtered.map((v) => <VisitRow key={v.id} visit={v} />)
        ) : (
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill,minmax(300px,1fr))",
              gap: 14,
            }}
          >
            {filtered.map((v) => (
              <VisitCard key={v.id} visit={v} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// ── App Shell (shared nav for all pages) ─────────────────────────────────────
// ── Hours Calendar Page ───────────────────────────────────────────────────────
// Duration string → decimal hours

// ── Chaplain Metrics Page ─────────────────────────────────────────────────────
// Definitions:
//   CD  = Chaplain Dialogue — meaningful 1:1 care conversation
//   CLI = Chaplain-Led Interaction — any engagement logged per visit
//   WSV = Workplace Service Visit — a full visit record
//   Engagements = total interaction count per WSV

function buildChaplainMetrics(user, allClients) {
  const visits = getVisitLog(allClients);
  const seed = (s) => {
    let h = 0;
    for (let c of s) h = (h * 31 + c.charCodeAt(0)) & 0xffffffff;
    return Math.abs(h);
  };

  // Filter to this chaplain's visits
  const lastName = user.name.split(" ").slice(-1)[0];
  const myVisits = visits.filter((v) =>
    v.chaplains.some((c) => c.includes(lastName)),
  );

  // CD interaction keys (meaningful 1:1 conversations)
  const CD_KEYS = new Set([
    "supportive",
    "grief",
    "crisis",
    "spiritual",
    "family",
    "health",
    "stress",
  ]);

  // Per-client rollup
  const clientMap = {};
  allClients.forEach((c) => {
    clientMap[c.id] = {
      id: c.id,
      name: c.name,
      color: c.color,
      logo: c.logo,
      // Assigned hours: derive from chaplain count & contract size
      hoursAssigned: Math.round(
        (c.employees / 100) * 2.4 + (seed(c.id + "hrs") % 20),
      ),
      hoursReported: 0,
      totalCDs: 0,
      totalEngagements: 0,
      totalCLIs: 0,
      totalWSVs: 0,
      months: {},
    };
  });

  myVisits.forEach((v) => {
    const cl = clientMap[v.clientId];
    if (!cl) return;
    const hrs = parseDuration(v.duration);
    cl.hoursReported += hrs;
    cl.totalWSVs += 1;
    cl.totalEngagements += v.totalInteractions;
    // CDs = sum of CD-type interactions
    let cds = 0;
    Object.entries(v.interactions || {}).forEach(([k, cnt]) => {
      cl.totalCLIs += cnt;
      if (CD_KEYS.has(k)) cds += cnt;
    });
    cl.totalCDs += cds;

    // Monthly breakdown
    const ym = v.date.slice(0, 7);
    if (!cl.months[ym])
      cl.months[ym] = { hrs: 0, cds: 0, engagements: 0, wsvs: 0, clis: 0 };
    cl.months[ym].hrs += hrs;
    cl.months[ym].cds += cds;
    cl.months[ym].engagements += v.totalInteractions;
    cl.months[ym].wsvs += 1;
    cl.months[ym].clis += Object.values(v.interactions || {}).reduce(
      (a, b) => a + b,
      0,
    );
  });

  const clients = Object.values(clientMap).filter(
    (c) => c.totalWSVs > 0 || c.hoursAssigned > 0,
  );

  // Totals
  const totals = clients.reduce(
    (acc, c) => ({
      hoursAssigned: acc.hoursAssigned + c.hoursAssigned,
      hoursReported: acc.hoursReported + c.hoursReported,
      totalCDs: acc.totalCDs + c.totalCDs,
      totalEngagements: acc.totalEngagements + c.totalEngagements,
      totalCLIs: acc.totalCLIs + c.totalCLIs,
      totalWSVs: acc.totalWSVs + c.totalWSVs,
    }),
    {
      hoursAssigned: 0,
      hoursReported: 0,
      totalCDs: 0,
      totalEngagements: 0,
      totalCLIs: 0,
      totalWSVs: 0,
    },
  );

  // Ratios (portfolio-level)
  const avgCDsPerHour =
    totals.hoursReported > 0
      ? (totals.totalCDs / totals.hoursReported).toFixed(2)
      : "—";
  const avgEngagementsPerHr =
    totals.hoursReported > 0
      ? (totals.totalEngagements / totals.hoursReported).toFixed(2)
      : "—";
  const avgCLIsPerWSV =
    totals.totalWSVs > 0
      ? (totals.totalCLIs / totals.totalWSVs).toFixed(1)
      : "—";

  // Trend chart: last 6 months
  const MONTHS = [
    "2024-08",
    "2024-09",
    "2024-10",
    "2024-11",
    "2024-12",
    "2025-01",
  ];
  const MONTH_LABELS = ["Aug", "Sep", "Oct", "Nov", "Dec", "Jan"];
  const trendData = MONTHS.map((ym, i) => {
    let hrs = 0,
      cds = 0,
      eng = 0,
      clis = 0,
      wsvs = 0;
    clients.forEach((c) => {
      const m = c.months[ym] || {};
      hrs += m.hrs || 0;
      cds += m.cds || 0;
      eng += m.engagements || 0;
      clis += m.clis || 0;
      wsvs += m.wsvs || 0;
    });
    return {
      month: MONTH_LABELS[i],
      cdPerHr: hrs > 0 ? parseFloat((cds / hrs).toFixed(2)) : 0,
      engPerHr: hrs > 0 ? parseFloat((eng / hrs).toFixed(2)) : 0,
      cliPerWSV: wsvs > 0 ? parseFloat((clis / wsvs).toFixed(1)) : 0,
      hoursRep: Math.round(hrs),
      hoursAsgn: Math.round(
        clients.reduce((a, c) => a + c.hoursAssigned / 6, 0),
      ),
    };
  });

  return {
    clients,
    totals,
    avgCDsPerHour,
    avgEngagementsPerHr,
    avgCLIsPerWSV,
    trendData,
  };
}

