// ── Tasks Page ─────────────────────────────────────────────────────────────────
function TasksPage({ user, allClients }) {
  const cc = "#1a4a7a";
  const myClientIds = new Set(allClients.map((c) => c.id));
  const isChaplain = user.role === "Chaplain";
  const [tasks, setTasks] = useState(TASKS_STORE);
  const [filterStatus, setFilterStatus] = useState("all");
  const [filterSource, setFilterSource] = useState("all");
  const [filterPriority, setFilterPriority] = useState("all");
  const [filterClient, setFilterClient] = useState("all");
  const [search, setSearch] = useState("");
  const [showForm, setShowForm] = useState(false);
  const [editTask, setEditTask] = useState(null);
  const [selectedTask, setSelectedTask] = useState(null);
  const [newTask, setNewTask] = useState({
    title: "",
    clientId: "",
    due: "",
    priority: "medium",
    category: "followup",
    notes: "",
    source: "portal",
  });

  // scope: chaplains see only their own assigned tasks
  const scoped = tasks.filter((t) =>
    user.role === "EVP" || user.role === "SVP" || user.role === "Exec"
      ? true
      : isChaplain
        ? t.assignee === user.name
        : !t.clientId || myClientIds.has(t.clientId),
  );

  const filtered = scoped.filter((t) => {
    if (filterStatus !== "all" && t.status !== filterStatus) return false;
    if (filterSource !== "all" && t.source !== filterSource) return false;
    if (filterPriority !== "all" && t.priority !== filterPriority) return false;
    if (filterClient !== "all" && t.clientId !== filterClient) return false;
    if (search) {
      const q = search.toLowerCase();
      return (
        t.title.toLowerCase().includes(q) ||
        t.clientName.toLowerCase().includes(q) ||
        (t.notes || "").toLowerCase().includes(q)
      );
    }
    return true;
  });

  const counts = { todo: 0, inprogress: 0, done: 0, overdue: 0 };
  scoped.forEach((t) => {
    if (counts[t.status] !== undefined) counts[t.status]++;
  });

  const PRIORITY_C = {
    urgent: { bg: "#fdedec", text: "#922b21", dot: "#e74c3c", label: "Urgent" },
    high: { bg: "#fef9e7", text: "#9a6e00", dot: "#f39c12", label: "High" },
    medium: { bg: "#eaf4ff", text: "#1a4a7a", dot: "#3b82f6", label: "Medium" },
    low: { bg: "#f0f4f8", text: "#6b7a8d", dot: "#b0bcc8", label: "Low" },
  };
  const STATUS_C = {
    todo: { bg: "#f0f4f8", text: "#6b7a8d", label: "To Do" },
    inprogress: { bg: "#eaf0ff", text: "#1a4a7a", label: "In Progress" },
    done: { bg: "#eafaf1", text: "#1e8449", label: "Done" },
    overdue: { bg: "#fdedec", text: "#922b21", label: "Overdue" },
  };
  const SOURCE_IC = { dynamics: "⚡", workday: "👥", portal: "✅" };
  const CAT_IC = {
    report: "📄",
    call: "📞",
    followup: "🔁",
    contract: "📋",
    visit: "🏢",
    hr: "👤",
    finance: "💰",
    training: "🎓",
    review: "🔍",
  };

  function cycleStatus(id) {
    const cycle = {
      todo: "inprogress",
      inprogress: "done",
      done: "todo",
      overdue: "inprogress",
    };
    setTasks((p) =>
      p.map((t) =>
        t.id === id ? { ...t, status: cycle[t.status] || "todo" } : t,
      ),
    );
  }

  function saveTask() {
    if (!newTask.title.trim()) return;
    const client = allClients.find((c) => c.id === newTask.clientId);
    if (editTask) {
      setTasks((p) =>
        p.map((t) =>
          t.id === editTask
            ? { ...t, ...newTask, clientName: client?.name || "Internal" }
            : t,
        ),
      );
    } else {
      setTasks((p) => [
        ...p,
        {
          ...newTask,
          id: "t" + taskNextId++,
          status: "todo",
          clientName: client?.name || "Internal",
          assignee: user.name,
          role: user.role,
          crmRef: null,
          wdRef: null,
        },
      ]);
    }
    setShowForm(false);
    setEditTask(null);
    setNewTask({
      title: "",
      clientId: "",
      due: "",
      priority: "medium",
      category: "followup",
      notes: "",
      source: "portal",
    });
  }

  function openEdit(t) {
    setNewTask({
      title: t.title,
      clientId: t.clientId || "",
      due: t.due,
      priority: t.priority,
      category: t.category,
      notes: t.notes || "",
      source: t.source,
    });
    setEditTask(t.id);
    setShowForm(true);
  }

  const inputS = {
    width: "100%",
    padding: "7px 10px",
    borderRadius: 7,
    border: "1px solid #d0dae6",
    fontSize: 12,
    boxSizing: "border-box",
    outline: "none",
    background: "#fff",
  };
  const selS = { ...inputS, cursor: "pointer" };

  const SOURCE_META = {
    dynamics: {
      icon: "⚡",
      label: "Dynamics 365 CRM",
      bg: "#e8f0ff",
      text: "#1a4a7a",
      desc: "Synced automatically from Microsoft Dynamics 365",
    },
    workday: {
      icon: "👥",
      label: "Workday",
      bg: "#eafaf1",
      text: "#1e8449",
      desc: "Synced automatically from Workday HR",
    },
    portal: {
      icon: "✅",
      label: "MM Portal",
      bg: "#f0f4f8",
      text: "#4a5568",
      desc: "Created manually in the Marketplace Ministries portal",
    },
  };

  // ── Task Detail Modal ──────────────────────────────────────────────────────
  function TaskDetailModal({ task, onClose }) {
    const PC = PRIORITY_C[task.priority] || PRIORITY_C.medium;
    const SC = STATUS_C[task.status] || STATUS_C.todo;
    const SM = SOURCE_META[task.source] || SOURCE_META.portal;
    const isOverdue =
      task.status !== "done" &&
      task.due &&
      new Date(task.due) < new Date("2025-01-16");

    return (
      <div
        onClick={onClose}
        style={{
          position: "fixed",
          inset: 0,
          background: "rgba(10,20,40,0.55)",
          zIndex: 600,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          padding: 24,
          backdropFilter: "blur(3px)",
        }}
      >
        <div
          onClick={(e) => e.stopPropagation()}
          style={{
            background: "#fff",
            borderRadius: 16,
            width: "100%",
            maxWidth: 560,
            maxHeight: "90vh",
            overflow: "hidden",
            boxShadow: "0 24px 64px rgba(0,0,0,0.22)",
            display: "flex",
            flexDirection: "column",
          }}
        >
          {/* Header */}
          <div
            style={{
              background: `linear-gradient(135deg,${PC.dot},${PC.dot}bb)`,
              padding: "20px 24px",
              color: "#fff",
              flexShrink: 0,
            }}
          >
            <div
              style={{
                display: "flex",
                alignItems: "flex-start",
                justifyContent: "space-between",
                gap: 12,
              }}
            >
              <div style={{ flex: 1, minWidth: 0 }}>
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 8,
                    marginBottom: 6,
                    flexWrap: "wrap",
                  }}
                >
                  <span
                    style={{
                      fontSize: 11,
                      fontWeight: 700,
                      padding: "2px 8px",
                      borderRadius: 6,
                      background: "rgba(255,255,255,0.25)",
                      letterSpacing: "0.06em",
                      textTransform: "uppercase",
                    }}
                  >
                    {PC.label}
                  </span>
                  <span
                    style={{
                      fontSize: 11,
                      fontWeight: 700,
                      padding: "2px 8px",
                      borderRadius: 6,
                      background: "rgba(255,255,255,0.2)",
                    }}
                  >
                    {SC.label}
                  </span>
                  {isOverdue && task.status !== "done" && (
                    <span
                      style={{
                        fontSize: 11,
                        fontWeight: 700,
                        padding: "2px 8px",
                        borderRadius: 6,
                        background: "rgba(231,76,60,0.5)",
                      }}
                    >
                      OVERDUE
                    </span>
                  )}
                </div>
                <div
                  style={{
                    fontSize: 17,
                    fontWeight: 700,
                    fontFamily: "'Georgia',serif",
                    lineHeight: 1.3,
                  }}
                >
                  {task.title}
                </div>
              </div>
              <button
                onClick={onClose}
                style={{
                  border: "none",
                  background: "rgba(255,255,255,0.2)",
                  borderRadius: 8,
                  width: 32,
                  height: 32,
                  cursor: "pointer",
                  fontSize: 16,
                  color: "#fff",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  flexShrink: 0,
                }}
              >
                ✕
              </button>
            </div>
          </div>

          {/* Body */}
          <div
            style={{
              flex: 1,
              overflow: "auto",
              padding: "20px 24px",
              display: "flex",
              flexDirection: "column",
              gap: 14,
            }}
          >
            {/* Key details grid */}
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr",
                gap: 10,
              }}
            >
              {[
                ["Assigned to", task.assignee],
                ["Due date", task.due || "No due date"],
                ["Client", task.clientName || "Internal"],
                ["Category", `${CAT_IC[task.category] || ""} ${task.category}`],
              ].map(([l, v]) => (
                <div
                  key={l}
                  style={{
                    background: "#f7f9fc",
                    borderRadius: 8,
                    padding: "10px 12px",
                  }}
                >
                  <div
                    style={{
                      fontSize: 10,
                      color: "#9aa8b8",
                      textTransform: "uppercase",
                      letterSpacing: "0.06em",
                      marginBottom: 3,
                    }}
                  >
                    {l}
                  </div>
                  <div
                    style={{ fontSize: 13, fontWeight: 600, color: "#1a2a3a" }}
                  >
                    {v}
                  </div>
                </div>
              ))}
            </div>

            {/* Notes */}
            {task.notes && (
              <div
                style={{
                  background: "#f7f9fc",
                  borderRadius: 10,
                  padding: "14px 16px",
                }}
              >
                <div
                  style={{
                    fontSize: 10,
                    fontWeight: 700,
                    color: "#9aa8b8",
                    textTransform: "uppercase",
                    letterSpacing: "0.07em",
                    marginBottom: 8,
                  }}
                >
                  Notes
                </div>
                <div
                  style={{ fontSize: 13, color: "#2c3e50", lineHeight: 1.75 }}
                >
                  {task.notes}
                </div>
              </div>
            )}

            {/* Source */}
            <div
              style={{
                background: SM.bg,
                borderRadius: 10,
                padding: "14px 16px",
                border: `1px solid ${SM.text}22`,
              }}
            >
              <div
                style={{
                  fontSize: 10,
                  fontWeight: 700,
                  color: "#9aa8b8",
                  textTransform: "uppercase",
                  letterSpacing: "0.07em",
                  marginBottom: 8,
                }}
              >
                Source
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <span style={{ fontSize: 20 }}>{SM.icon}</span>
                <div>
                  <div
                    style={{ fontSize: 13, fontWeight: 700, color: SM.text }}
                  >
                    {SM.label}
                  </div>
                  <div style={{ fontSize: 11, color: "#9aa8b8", marginTop: 2 }}>
                    {SM.desc}
                  </div>
                </div>
              </div>
              {(task.crmRef || task.wdRef) && (
                <div
                  style={{
                    fontSize: 11,
                    color: SM.text,
                    marginTop: 8,
                    fontWeight: 600,
                  }}
                >
                  Ref: {task.crmRef || task.wdRef}
                </div>
              )}
            </div>
          </div>

          {/* Footer actions */}
          <div
            style={{
              padding: "14px 24px",
              borderTop: "1px solid #e8edf2",
              display: "flex",
              gap: 8,
              justifyContent: "space-between",
              alignItems: "center",
              flexShrink: 0,
            }}
          >
            <button
              onClick={() => {
                cycleStatus(task.id);
                setSelectedTask((t) =>
                  t
                    ? {
                        ...t,
                        status:
                          {
                            todo: "inprogress",
                            inprogress: "done",
                            done: "todo",
                            overdue: "inprogress",
                          }[t.status] || "todo",
                      }
                    : null,
                );
              }}
              style={{
                padding: "8px 16px",
                borderRadius: 8,
                border: `1.5px solid ${SC.text}`,
                background: "transparent",
                color: SC.text,
                fontSize: 12,
                fontWeight: 700,
                cursor: "pointer",
              }}
            >
              {task.status === "todo"
                ? "▶ Start"
                : task.status === "inprogress"
                  ? "✓ Mark done"
                  : task.status === "done"
                    ? "↩ Reopen"
                    : "▶ Restart"}
            </button>
            <div style={{ display: "flex", gap: 8 }}>
              <button
                onClick={() => {
                  openEdit(task);
                  onClose();
                }}
                style={{
                  padding: "8px 16px",
                  borderRadius: 8,
                  border: "1px solid #d0dae6",
                  background: "#fff",
                  color: "#6b7a8d",
                  fontSize: 12,
                  fontWeight: 600,
                  cursor: "pointer",
                }}
              >
                ✏️ Edit
              </button>
              <button
                onClick={onClose}
                style={{
                  padding: "8px 16px",
                  borderRadius: 8,
                  border: "none",
                  background: cc,
                  color: "#fff",
                  fontSize: 12,
                  fontWeight: 700,
                  cursor: "pointer",
                }}
              >
                Close
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={{ padding: "24px 28px", maxWidth: 1200, margin: "0 auto" }}>
      {selectedTask && (
        <TaskDetailModal
          task={selectedTask}
          onClose={() => setSelectedTask(null)}
        />
      )}
      {/* Header */}
      <div
        style={{
          display: "flex",
          alignItems: "flex-start",
          justifyContent: "space-between",
          marginBottom: 20,
          flexWrap: "wrap",
          gap: 12,
        }}
      >
        <div>
          <h1
            style={{
              fontSize: 24,
              fontWeight: 700,
              color: "#1a2a3a",
              fontFamily: "'Georgia',serif",
              margin: 0,
            }}
          >
            ✅ Tasks
          </h1>
          <p style={{ fontSize: 13, color: "#6b7a8d", marginTop: 4 }}>
            Synced with Dynamics 365 CRM and Workday — plus your own portal
            tasks.
          </p>
        </div>
        <button
          onClick={() => {
            setShowForm(true);
            setEditTask(null);
          }}
          style={{
            padding: "9px 18px",
            borderRadius: 9,
            border: "none",
            background: "#1a4a7a",
            color: "#fff",
            fontSize: 13,
            fontWeight: 700,
            cursor: "pointer",
          }}
        >
          + New Task
        </button>
      </div>

      {/* KPI strip */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(5,1fr)",
          gap: 10,
          marginBottom: 20,
        }}
      >
        {[
          {
            label: "Total Tasks",
            val: scoped.length,
            col: "#1a4a7a",
            bg: "#eaf0ff",
          },
          { label: "To Do", val: counts.todo, col: "#6b7a8d", bg: "#f0f4f8" },
          {
            label: "In Progress",
            val: counts.inprogress,
            col: "#2563eb",
            bg: "#eaf0ff",
          },
          {
            label: "⚠️ Overdue",
            val: counts.overdue,
            col: "#922b21",
            bg: "#fdedec",
          },
          { label: "✓ Done", val: counts.done, col: "#1e8449", bg: "#eafaf1" },
        ].map((k, i) => (
          <div
            key={i}
            style={{
              background: k.bg,
              borderRadius: 10,
              padding: "12px 14px",
              textAlign: "center",
              border: `1px solid ${k.col}22`,
              cursor: "pointer",
            }}
            onClick={() =>
              setFilterStatus(
                i === 0
                  ? "all"
                  : ["all", "todo", "inprogress", "overdue", "done"][i],
              )
            }
          >
            <div
              style={{
                fontSize: 24,
                fontWeight: 700,
                color: k.col,
                fontFamily: "'Georgia',serif",
                lineHeight: 1,
              }}
            >
              {k.val}
            </div>
            <div
              style={{
                fontSize: 10,
                color: k.col,
                fontWeight: 700,
                marginTop: 4,
                textTransform: "uppercase",
                letterSpacing: "0.06em",
              }}
            >
              {k.label}
            </div>
          </div>
        ))}
      </div>

      {/* Integration badges */}
      <div
        style={{
          display: "flex",
          gap: 8,
          marginBottom: 16,
          flexWrap: "wrap",
          alignItems: "center",
        }}
      >
        <div style={{ fontSize: 11, color: "#6b7a8d", fontWeight: 600 }}>
          Integrations:
        </div>
        {[
          ["dynamics", "⚡", "Dynamics 365", "#e8f0ff", "#1a4a7a"],
          ["workday", "👥", "Workday", "#f0fff4", "#1e8449"],
          ["portal", "✅", "MM Portal", "#f7f9fc", "#6b7a8d"],
        ].map(([src, ic, lbl, bg, col]) => (
          <div
            key={src}
            onClick={() => setFilterSource(filterSource === src ? "all" : src)}
            style={{
              display: "flex",
              alignItems: "center",
              gap: 5,
              padding: "4px 10px",
              borderRadius: 7,
              background: filterSource === src ? col : bg,
              color: filterSource === src ? "#fff" : col,
              fontSize: 11,
              fontWeight: 600,
              cursor: "pointer",
              border: `1px solid ${col}33`,
              transition: "all 0.15s",
            }}
          >
            {ic} {lbl}{" "}
            <span style={{ fontWeight: 400, opacity: 0.7 }}>
              ({scoped.filter((t) => t.source === src).length})
            </span>
          </div>
        ))}
        <div
          style={{
            marginLeft: "auto",
            display: "flex",
            gap: 6,
            alignItems: "center",
          }}
        >
          <div
            style={{
              width: 7,
              height: 7,
              borderRadius: "50%",
              background: "#27ae60",
            }}
          />
          <span style={{ fontSize: 11, color: "#6b7a8d" }}>
            Live sync active
          </span>
        </div>
      </div>

      {/* Filters + search */}
      <div
        style={{
          display: "flex",
          gap: 6,
          marginBottom: 16,
          alignItems: "center",
        }}
      >
        <div style={{ position: "relative", flex: "0 0 180px" }}>
          <span
            style={{
              position: "absolute",
              left: 9,
              top: "50%",
              transform: "translateY(-50%)",
              fontSize: 13,
              color: "#9aa8b8",
            }}
          >
            🔍
          </span>
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search tasks..."
            style={{ ...inputS, paddingLeft: 28 }}
          />
        </div>
        {[
          [
            filterStatus,
            setFilterStatus,
            [
              ["all", "All Status"],
              ["todo", "To Do"],
              ["inprogress", "In Progress"],
              ["overdue", "Overdue"],
              ["done", "Done"],
            ],
          ],
          [
            filterPriority,
            setFilterPriority,
            [
              ["all", "All Priority"],
              ["urgent", "Urgent"],
              ["high", "High"],
              ["medium", "Medium"],
              ["low", "Low"],
            ],
          ],
          [
            filterClient,
            setFilterClient,
            [["all", "All Clients"], ...allClients.map((c) => [c.id, c.name])],
          ],
        ].map(([val, setter, opts], i) => (
          <select
            key={i}
            value={val}
            onChange={(e) => setter(e.target.value)}
            style={{ ...selS, flex: "0 0 auto", minWidth: 0, maxWidth: 150 }}
          >
            {opts.map(([v, l]) => (
              <option key={v} value={v}>
                {l}
              </option>
            ))}
          </select>
        ))}
      </div>

      {/* New / edit task form */}
      {showForm && (
        <div
          style={{
            background: "#fff",
            border: "1px solid #e0e6ef",
            borderRadius: 12,
            padding: "18px 20px",
            marginBottom: 20,
            boxShadow: "0 4px 20px rgba(0,0,0,0.08)",
          }}
        >
          <div
            style={{
              fontSize: 13,
              fontWeight: 700,
              color: "#1a2a3a",
              marginBottom: 14,
            }}
          >
            {editTask ? "✏️ Edit Task" : "+ New Task"}
          </div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: 10,
              marginBottom: 10,
            }}
          >
            <div style={{ gridColumn: "1/-1" }}>
              <input
                value={newTask.title}
                onChange={(e) =>
                  setNewTask((p) => ({ ...p, title: e.target.value }))
                }
                placeholder="Task title *"
                style={inputS}
              />
            </div>
            <select
              value={newTask.clientId}
              onChange={(e) =>
                setNewTask((p) => ({ ...p, clientId: e.target.value }))
              }
              style={selS}
            >
              <option value="">No specific client</option>
              {allClients.map((c) => (
                <option key={c.id} value={c.id}>
                  {c.name}
                </option>
              ))}
            </select>
            <input
              type="date"
              value={newTask.due}
              onChange={(e) =>
                setNewTask((p) => ({ ...p, due: e.target.value }))
              }
              style={inputS}
            />
            <select
              value={newTask.priority}
              onChange={(e) =>
                setNewTask((p) => ({ ...p, priority: e.target.value }))
              }
              style={selS}
            >
              {["urgent", "high", "medium", "low"].map((v) => (
                <option key={v} value={v}>
                  {v.charAt(0).toUpperCase() + v.slice(1)}
                </option>
              ))}
            </select>
            <select
              value={newTask.category}
              onChange={(e) =>
                setNewTask((p) => ({ ...p, category: e.target.value }))
              }
              style={selS}
            >
              {Object.entries(CAT_IC).map(([v, ic]) => (
                <option key={v} value={v}>
                  {ic} {v.charAt(0).toUpperCase() + v.slice(1)}
                </option>
              ))}
            </select>
            <div style={{ gridColumn: "1/-1" }}>
              <textarea
                value={newTask.notes}
                onChange={(e) =>
                  setNewTask((p) => ({ ...p, notes: e.target.value }))
                }
                placeholder="Notes..."
                rows={2}
                style={{ ...inputS, resize: "vertical", fontFamily: "inherit" }}
              />
            </div>
          </div>
          <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
            <button
              onClick={() => {
                setShowForm(false);
                setEditTask(null);
              }}
              style={{
                padding: "7px 16px",
                borderRadius: 7,
                border: "1px solid #d0dae6",
                background: "#fff",
                color: "#6b7a8d",
                fontSize: 12,
                cursor: "pointer",
              }}
            >
              Cancel
            </button>
            <button
              onClick={saveTask}
              style={{
                padding: "7px 18px",
                borderRadius: 7,
                border: "none",
                background: "#1a4a7a",
                color: "#fff",
                fontSize: 12,
                fontWeight: 700,
                cursor: "pointer",
              }}
            >
              Save Task
            </button>
          </div>
        </div>
      )}

      {/* Task list */}
      <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
        {filtered.length === 0 && (
          <div
            style={{
              textAlign: "center",
              padding: "40px",
              color: "#9aa8b8",
              background: "#fff",
              borderRadius: 12,
              border: "1px solid #e8edf2",
            }}
          >
            <div style={{ fontSize: 32, marginBottom: 8 }}>✅</div>
            <div style={{ fontSize: 13, fontWeight: 600 }}>
              No tasks match your filters
            </div>
          </div>
        )}
        {filtered.map((task) => {
          const PC = PRIORITY_C[task.priority] || PRIORITY_C.medium;
          const SC = STATUS_C[task.status] || STATUS_C.todo;
          const isOverdue =
            task.status !== "done" &&
            task.due &&
            new Date(task.due) < new Date("2025-01-16");
          return (
            <div
              key={task.id}
              onClick={() => setSelectedTask(task)}
              style={{
                background: "#fff",
                border: "1px solid #e8edf2",
                borderRadius: 12,
                padding: "14px 16px",
                display: "flex",
                gap: 12,
                alignItems: "flex-start",
                transition: "all 0.15s",
                borderLeft: `4px solid ${PC.dot}`,
                cursor: "pointer",
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.boxShadow = "0 4px 16px rgba(0,0,0,0.08)";
                e.currentTarget.style.borderColor = PC.dot;
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.boxShadow = "none";
                e.currentTarget.style.borderColor = "#e8edf2";
              }}
            >
              {/* Status toggle circle — stop propagation so it doesn't open modal */}
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  cycleStatus(task.id);
                }}
                title="Click to advance status"
                style={{
                  width: 22,
                  height: 22,
                  borderRadius: "50%",
                  border: `2px solid ${SC.text}`,
                  background: task.status === "done" ? SC.text : "transparent",
                  cursor: "pointer",
                  flexShrink: 0,
                  marginTop: 2,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: 11,
                  color: task.status === "done" ? "#fff" : SC.text,
                  transition: "all 0.15s",
                }}
              >
                {task.status === "done" ? "✓" : ""}
              </button>

              <div style={{ flex: 1, minWidth: 0 }}>
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 8,
                    marginBottom: 4,
                    flexWrap: "wrap",
                  }}
                >
                  <span
                    style={{
                      fontSize: 13,
                      fontWeight: 700,
                      color: task.status === "done" ? "#9aa8b8" : "#1a2a3a",
                      textDecoration:
                        task.status === "done" ? "line-through" : "none",
                    }}
                  >
                    {task.title}
                  </span>
                  {isOverdue && task.status !== "done" && (
                    <span
                      style={{
                        fontSize: 10,
                        background: "#fdedec",
                        color: "#922b21",
                        padding: "1px 6px",
                        borderRadius: 5,
                        fontWeight: 700,
                      }}
                    >
                      OVERDUE
                    </span>
                  )}
                </div>
                <div
                  style={{
                    display: "flex",
                    gap: 6,
                    flexWrap: "wrap",
                    alignItems: "center",
                    marginBottom: task.notes ? 6 : 0,
                  }}
                >
                  {/* Source badge */}
                  <div
                    style={{
                      fontSize: 10,
                      padding: "2px 7px",
                      borderRadius: 6,
                      background: "#f0f4f8",
                      color: "#6b7a8d",
                      fontWeight: 600,
                    }}
                  >
                    {SOURCE_IC[task.source]} {TASK_SOURCES[task.source]}
                    {task.crmRef && (
                      <span style={{ opacity: 0.6 }}> · {task.crmRef}</span>
                    )}
                    {task.wdRef && (
                      <span style={{ opacity: 0.6 }}> · {task.wdRef}</span>
                    )}
                  </div>
                  {/* Category */}
                  <div
                    style={{
                      fontSize: 10,
                      padding: "2px 7px",
                      borderRadius: 6,
                      background: "#f7f9fc",
                      color: "#4a5568",
                    }}
                  >
                    {CAT_IC[task.category]} {task.category}
                  </div>
                  {/* Client */}
                  {task.clientName && (
                    <div
                      style={{
                        fontSize: 10,
                        padding: "2px 7px",
                        borderRadius: 6,
                        background: "#eaf0ff",
                        color: "#1a4a7a",
                      }}
                    >
                      🏢 {task.clientName}
                    </div>
                  )}
                  {/* Assignee */}
                  <div style={{ fontSize: 10, color: "#9aa8b8" }}>
                    → {task.assignee}
                  </div>
                </div>
                {task.notes && (
                  <div
                    style={{
                      fontSize: 11,
                      color: "#6b7a8d",
                      lineHeight: 1.5,
                      fontStyle: "italic",
                      overflow: "hidden",
                      display: "-webkit-box",
                      WebkitLineClamp: 2,
                      WebkitBoxOrient: "vertical",
                    }}
                  >
                    {task.notes}
                  </div>
                )}
              </div>

              {/* Right: due + priority + status */}
              <div
                style={{
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "flex-end",
                  gap: 5,
                  flexShrink: 0,
                }}
              >
                {task.due && (
                  <div
                    style={{
                      fontSize: 11,
                      color:
                        isOverdue && task.status !== "done"
                          ? "#922b21"
                          : "#9aa8b8",
                      fontWeight: isOverdue ? 700 : 400,
                    }}
                  >
                    📅 {task.due}
                  </div>
                )}
                <div
                  style={{
                    fontSize: 10,
                    padding: "2px 8px",
                    borderRadius: 6,
                    background: PC.bg,
                    color: PC.text,
                    fontWeight: 700,
                  }}
                >
                  {PC.label}
                </div>
                <div
                  style={{
                    fontSize: 10,
                    padding: "2px 8px",
                    borderRadius: 6,
                    background: SC.bg,
                    color: SC.text,
                    fontWeight: 600,
                  }}
                >
                  {SC.label}
                </div>
                <span style={{ fontSize: 10, color: "#c8d0da" }}>›</span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

