                  <div
                    style={{
                      fontSize: 10,
                      fontWeight: 700,
                      color: "#9aa8b8",
                      textTransform: "uppercase",
                      letterSpacing: "0.07em",
                      marginBottom: 8,
                    }}
                  >
                    Accounts
                  </div>
